  `designation` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `numero` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `numero_cheque` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `piece_jointe` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ordonnateur` enum('COMPTABLE','MANAGER') COLLATE utf8mb4_unicode_ci NOT NULL,
  `source` enum('BANQUE','CAISSE','DETTE','MOBILE_MONEY') COLLATE utf8mb4_unicode_ci NOT NULL,
  `type_charge` enum('CHARGE_FIXE','CHARGE_VARIABLE','INVESTISSEMENT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `categorie_liee_id` bigint DEFAULT NULL,
  `ordonnateur_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `FKsryu7m3j8ffnhhmry5ee1r49u` (`categorie_depense_id`),
  KEY `FKtcyy26xooxcs2fv2e5c4jkdur` (`cree_par_id`),
  KEY `FK3elam5n6ua7tbx2dhvk69scq2` (`entreprise_id`),
  KEY `FKnq3l05k3ngje9x1qa2d30mc7p` (`fournisseur_id`),
  KEY `FK2olmuxjxxo4kod8i2vn94mn61` (`produit_id`),
  KEY `FKmw6v8xvnd1vhgb3eae2cslk9l` (`categorie_liee_id`),
  CONSTRAINT `FK2olmuxjxxo4kod8i2vn94mn61` FOREIGN KEY (`produit_id`) REFERENCES `produit` (`id`),
  CONSTRAINT `FK3elam5n6ua7tbx2dhvk69scq2` FOREIGN KEY (`entreprise_id`) REFERENCES `entreprise` (`id`),
  CONSTRAINT `FKmw6v8xvnd1vhgb3eae2cslk9l` FOREIGN KEY (`categorie_liee_id`) REFERENCES `categorie` (`id`),
  CONSTRAINT `FKnq3l05k3ngje9x1qa2d30mc7p` FOREIGN KEY (`fournisseur_id`) REFERENCES `fournisseur` (`id`),
  CONSTRAINT `FKsryu7m3j8ffnhhmry5ee1r49u` FOREIGN KEY (`categorie_depense_id`) REFERENCES `categorie_depense` (`id`),
  CONSTRAINT `FKtcyy26xooxcs2fv2e5c4jkdur` FOREIGN KEY (`cree_par_id`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=410 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
