CREATE TABLE `entree_generale` (
  `montant` double NOT NULL,
  `montant_reste` double DEFAULT NULL,
  `prix_unitaire` double NOT NULL,
  `quantite` int NOT NULL,
  `categorie_id` bigint DEFAULT NULL,
  `cree_par_id` bigint NOT NULL,
  `date_creation` datetime(6) NOT NULL,
  `dette_id` bigint DEFAULT NULL,
  `entreprise_id` bigint NOT NULL,
  `id` bigint NOT NULL AUTO_INCREMENT,
  `responsable_id` bigint NOT NULL,
  `dette_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `designation` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `dette_numero` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `numero` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `numero_mode_entree` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `piece_jointe` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mode_entree` enum('AUTRE','CARTE','CHEQUE','CREDIT','ESPECES','MOBILE_MONEY','RETRAIT','VIREMENT') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source` enum('BANQUE','CAISSE','DETTE','MOBILE_MONEY') COLLATE utf8mb4_unicode_ci NOT NULL,
  `dette_type_origine` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FK6qx8gu1k566b74i418no7o6oc` (`categorie_id`),
  KEY `FKqdh57gqiuaba78jrfk0podeds` (`cree_par_id`),
  KEY `FK9sux7ltluyg2f7anb55tnqtd8` (`entreprise_id`),
  KEY `FK1tjk1hbdp5y8wvqy4vp3h3r7` (`responsable_id`),
  CONSTRAINT `FK1tjk1hbdp5y8wvqy4vp3h3r7` FOREIGN KEY (`responsable_id`) REFERENCES `user` (`id`),
  CONSTRAINT `FK6qx8gu1k566b74i418no7o6oc` FOREIGN KEY (`categorie_id`) REFERENCES `categorie` (`id`),
  CONSTRAINT `FK9sux7ltluyg2f7anb55tnqtd8` FOREIGN KEY (`entreprise_id`) REFERENCES `entreprise` (`id`),
  CONSTRAINT `FKqdh57gqiuaba78jrfk0podeds` FOREIGN KEY (`cree_par_id`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=185 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
