CREATE TABLE `entreprise` (
  `active` bit(1) DEFAULT NULL,
  `taux_tva` double DEFAULT NULL,
  `admin_id` bigint DEFAULT NULL,
  `created_at` datetime(6) NOT NULL,
  `date_fin_essai_modules_payants` datetime(6) DEFAULT NULL,
