INSERT INTO `note_facture_pro_forma` VALUES (_binary '\0',34,'2026-01-12 16:34:33.032397',NULL,22,1,'Bonjour Hady Fofana\n','N 1',NULL),(_binary '\0',27,'2026-01-14 16:58:41.064075',NULL,26,2,'Mettre les formation individuelles à 200.000f chacune','N 1',NULL),(_binary '\0',27,'2026-01-16 12:08:37.463516',NULL,30,4,'Met une explication dans la note ','N 1',NULL),(_binary '\0',28,'2026-01-16 12:20:35.167185',NULL,30,5,'M. Abdoulaye ONGOIBA nous a contacté qu\'il souhaiterait faire former son fils de 18 ans en classe de 11 année, sur un programme sur mesure.\n','N 2',NULL),(_binary '\0',28,'2026-01-16 12:20:51.559203',NULL,30,6,'Ils sont à Koulikoro et le M. est militaire, qu\'il souhaiterait avoir un proforma pour se programmer et envoyer son enfant pendant le mois de Juin qui correspond à leur congé.','N 3',NULL),(_binary '\0',28,'2026-01-16 17:35:53.861917',NULL,31,7,'Bien recu !','N 1',NULL),(_binary '\0',28,'2026-01-21 19:02:00.011448',NULL,26,8,'bIEN RECU','N 2',NULL),(_binary '\0',27,'2026-01-23 08:35:59.992057',NULL,38,9,'Je valide ','N 1',NULL),(_binary '\0',31,'2026-01-26 15:16:16.735708',NULL,41,10,'C\'est un client qui vient de lancer son entreprise et qui est à ses debut à qui on a deja eloborer le reglement interieur, récruter un comptable et vendu un ordinateur hp core i5, maintenant il souhaite qu\'on l\'accompagne pour la communication de son entreprise','N 1',NULL),(_binary '',27,'2026-01-26 15:26:28.985526','2026-01-26 15:26:44.549917',41,12,'Il faut rajouter  la conception d\'une affiche pour lui. ','N 2',NULL),(_binary '\0',31,'2026-01-26 15:47:23.934666',NULL,41,13,'Il y\'a la conception d\'affiche dans enregistrement du spot publicitaire','N 3',NULL),(_binary '\0',27,'2026-01-27 12:15:33.795890',NULL,43,14,'IL manque la conception des outils ','N 1',NULL),(_binary '\0',28,'2026-01-29 12:41:40.487167',NULL,46,16,'Impression Casquette 1500F par Casquette cout de production,\nImpression Gillet qualité lourde 7000F cout de production,\nImpression Gillet qualité standard 7000F Cout de production,\nImpression Flyers 200F/Unité Cout de production\n','N 2',NULL),(_binary '\0',27,'2026-01-29 12:51:41.166272',NULL,46,17,'Il faut revoir les prix. Car les quantités sont trop petits. Les prix qui sont là sont pour les grandes capacités. \n','N 3',NULL),(_binary '\0',27,'2026-01-29 19:53:22.237543',NULL,49,18,'C’est bon ','N 1',NULL),(_binary '\0',27,'2026-01-31 12:49:21.202062',NULL,50,19,'Je vois une l\'application en plus de Excel ','N 1',NULL),(_binary '\0',28,'2026-02-04 12:20:36.137359',NULL,51,20,'Bonjour \nM. Thera est Ingénieur Télécom \nEt il souhaiterait avoir un devis sur la formation Art Oratoire','N 1',NULL),(_binary '\0',27,'2026-02-04 12:22:52.591946',NULL,51,21,'il faut corriger l\'objet, prise de parole ','N 2',NULL),(_binary '\0',27,'2026-02-05 20:15:03.960880',NULL,23,22,'Sur site doit se retourner à Bamako en mois de Mars 2026. Le relancer pour cela','N 1',NULL),(_binary '\0',28,'2026-02-09 16:22:17.678182',NULL,59,23,'Un client Souhaiterait avoir une facture proforma pour nos services de la communication.\nJ\'ai deja rajouté nos marges sur tous les services.','N 1',27),(_binary '\0',27,'2026-02-10 11:56:47.593573',NULL,59,24,'C\'est bon pour moi ','N 2',28),(_binary '\0',28,'2026-02-10 12:29:34.895097',NULL,62,25,'Bonjour\nAlassane souhaiterait avoir une facture pour un ami pour la conception des cartes de membre pour leur association.','N 1',27),(_binary '\0',27,'2026-02-10 12:32:00.254211',NULL,62,26,'il faut faire simplement 1000f par cartes avec pochette','N 2',28),(_binary '\0',28,'2026-02-10 12:43:18.163601',NULL,62,27,'La facture mis à jour','N 3',27),(_binary '\0',33,'2026-02-10 12:46:27.072622',NULL,63,28,'Test note','N 1',34),(_binary '\0',27,'2026-02-12 17:33:54.503478',NULL,71,29,'Les bâches sont 2m X 1m ( 20000f  )','N 1',28),(_binary '\0',27,'2026-02-12 17:34:47.072731',NULL,71,30,'Je viens de voir l\'imppression à part. Donc c\'est bon ','N 2',28),(_binary '\0',28,'2026-02-12 17:47:31.789802',NULL,72,31,'Tu vas l\'envoyer ?','N 1',27),(_binary '\0',27,'2026-02-13 11:44:41.685598',NULL,74,32,'Tu peux lui envoyer','N 1',28),(_binary '\0',27,'2026-02-13 11:59:56.831319',NULL,73,33,'Bonjour, je valide ','N 1',28),(_binary '\0',28,'2026-02-13 16:39:31.321135',NULL,59,34,'J\'attends la validation pour envoyer ','N 3',27),(_binary '\0',27,'2026-02-16 14:21:31.734334',NULL,80,35,'M. Thiam souhaite une deuxième formation pour ses enfants ','N 1',28),(_binary '\0',28,'2026-02-16 15:08:43.389854',NULL,81,36,'La facture du jeune homme qui est passé aujourd\'hui, il veut faire une video de publicitaire et 10 petipes vides explicatives des fonctiannalités','N 1',27),(_binary '\0',28,'2026-02-16 15:10:56.123257',NULL,80,37,'Bien recu, on peut l\'envoyer','N 2',27),(_binary '\0',27,'2026-02-16 17:07:28.787896',NULL,81,38,'Il faut lui faire le tout à 150.000fcfa le tout','N 2',28),(_binary '\0',28,'2026-02-16 17:17:20.912315',NULL,82,39,'Un client souhaiterait qu\'on l\'aide avec certains de ses documents pour mettre son logo dessus ','N 1',27),(_binary '\0',28,'2026-02-17 09:50:41.435823',NULL,59,40,'M. Diaby souhaiterait qu\'on enleve les pannaux publicitaires et faire 3 Plaque lumineux en plexiglass.\nJ\'ai deja modifié, tu peux verifier','N 4',27),(_binary '\0',27,'2026-02-17 10:28:18.704350',NULL,83,41,'Avez-vous demandez le prix des micro cravates de qualité supérieur ? ','N 1',28),(_binary '\0',27,'2026-02-17 10:29:43.120885',NULL,81,42,'Je valide, il faut lui envoyer. S\'il a 50.000fcfa ont peut enregistrer et il paiera le reste plus tard comme il peut. ','N 3',28),(_binary '\0',27,'2026-02-17 10:34:04.121404',NULL,29,43,'Propose après le mois de Ramadan','N 1',27),(_binary '\0',27,'2026-02-17 11:02:13.835146',NULL,59,44,'Je ne vois qu\'une seul plaque lumineuse dans le proforma','N 5',28),(_binary '',28,'2026-02-17 11:57:19.914294','2026-02-17 11:58:36.720821',83,45,'Oui c\'est le meme que tu fait tes enregistrements','N 2',28),(_binary '\0',28,'2026-02-17 11:58:42.692872',NULL,83,46,'Oui c\'est le meme que tu fait tes enregistrements','N 3',27),(_binary '\0',28,'2026-02-17 11:59:50.238693',NULL,83,47,'Trépied avec Ring Light de 22 pouces,  Le fournisseur nous donne à 30 000F et le Micro Cravate il nous donne à 15 000F','N 4',28),(_binary '\0',28,'2026-02-17 12:00:05.892982',NULL,83,48,'Trépied avec Ring Light de 22 pouces,  Le fournisseur nous donne à 30 000F et le Micro Cravate il nous donne à 15 000F','N 5',27),(_binary '\0',28,'2026-02-17 12:02:12.942210',NULL,81,49,'Ok','N 4',27),(_binary '\0',27,'2026-02-17 14:39:50.492754',NULL,87,50,'Je valide ','N 1',28),(_binary '',28,'2026-02-23 15:31:50.893693','2026-02-23 15:33:53.155131',135,52,'Bonjour \nM. Bruno OUOLOGUEM est passé ce matin pour des besoins en formation, sur le Logiciel de comptabilité Sage et Odoo.\nC\'est un particulier souhaitant ce former sur ces modules','N 1',27),(_binary '\0',27,'2026-02-23 16:24:49.453563',NULL,135,53,'Il faut mettre la formation Oddoo à 150.000fcfa ','N 2',28),(_binary '\0',27,'2026-02-24 15:45:58.576938',NULL,137,54,'Il souhaite envoyer son petit frère de Koutiala pour la formation de trois jours à Xpertpro sur le logiciel. Il fera le paiement sur place ','N 1',28),(_binary '\0',28,'2026-02-24 16:48:15.773822',NULL,137,55,'Bonjour \nBien recu, \nQuel jour il sera là ?','N 2',27),(_binary '\0',28,'2026-02-24 16:48:16.309131',NULL,137,56,'Bonjour \nBien recu, \nQuel jour il sera là ?','N 3',27),(_binary '\0',28,'2026-02-24 16:48:16.309027',NULL,137,57,'Bonjour \nBien recu, \nQuel jour il sera là ?','N 3',27),(_binary '\0',28,'2026-02-24 16:50:53.687698',NULL,137,58,'Je dois l\'envoyer la facture ?','N 4',27),(_binary '\0',28,'2026-02-24 17:33:41.810687',NULL,138,59,'Bonjour \nElle a rappelé et elle a demandé une remise, \nOn s\'est convenu sur 250 000F et Keita va passé demain pour l\'installation','N 1',27),(_binary '\0',27,'2026-02-26 17:28:19.493385',NULL,73,60,'Dans une semaine. Souhaite une reduction ','N 2',27),(_binary '\0',27,'2026-02-28 15:07:35.929792',NULL,144,61,'Il faut revoir la désignation ( Elaboration d\'un Terme de reférence. Et corriger la description.','N 1',28),(_binary '',28,'2026-02-28 15:18:22.265050','2026-02-28 15:18:39.680616',144,62,'C\'est fait','N 2',28),(_binary '\0',61,'2026-03-02 15:05:52.895479',NULL,148,63,'Je pense qu\'il faut augmenter le prix','N 1',62),(_binary '\0',27,'2026-03-10 02:01:47.757746',NULL,165,64,'Il souhaite le faire le 1er et le 2 Avril ','N 1',28),(_binary '\0',27,'2026-03-10 02:11:21.829541',NULL,166,65,'Il souhaite le faire après le mois de Ramadan ','N 1',28),(_binary '\0',27,'2026-03-10 02:13:17.025621',NULL,166,66,'Il souhaite le faire après le mois de Ramadan ','N 2',28),(_binary '\0',28,'2026-03-10 09:10:09.549007',NULL,166,67,'Bonjour \nBien recu ','N 3',27),(_binary '\0',28,'2026-03-10 09:33:50.265605',NULL,165,68,'Bonjour \nBien reçu \nJ\'envoie la facture au client ?','N 2',27),(_binary '\0',28,'2026-03-10 14:39:26.511285',NULL,170,69,'Les beneficiaires sont des etudiants \nEt c\'est la meme personne qui doit payer \nDonc je lui ai accordé 25 000F de remise sur l\'informatique\n','N 1',27);
