DROP TABLE IF EXISTS `vente`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vente` (
  `montant_paye` double DEFAULT NULL,
  `montant_total` double DEFAULT NULL,
  `montant_total_rembourse` double DEFAULT NULL,
  `nombre_remboursements` int DEFAULT NULL,
  `remise_globale` double DEFAULT NULL,
  `boutique_id` bigint DEFAULT NULL,
  `caisse_id` bigint DEFAULT NULL,
  `client_id` bigint DEFAULT NULL,
  `date_dernier_remboursement` datetime(6) DEFAULT NULL,
  `date_vente` datetime(6) DEFAULT NULL,
  `entreprise_client_id` bigint DEFAULT NULL,
  `id` bigint NOT NULL AUTO_INCREMENT,
  `vendeur_id` bigint DEFAULT NULL,
  `client_nom` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `client_numero` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mode_paiement` enum('AUTRE','CARTE','CHEQUE','CREDIT','ESPECES','MOBILE_MONEY','RETRAIT','VIREMENT') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('EN_COURS','PARTIELLEMENT_REMBOURSEE','PAYEE','REMBOURSEE') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FKj4jrmdev5qkq749n1kr4y0h3n` (`boutique_id`),
  KEY `FKjmaw7sj2qhcq1ly8xbiqkjbvo` (`caisse_id`),
  KEY `FKt8c0ckr8dqeq9nia3wb7j6r7n` (`client_id`),
  KEY `FKhfpb3rh3tmdf0i9ibyfddsavv` (`entreprise_client_id`),
  KEY `FKqo5gk9u6opb1ng6jobfli7ld4` (`vendeur_id`),
  CONSTRAINT `FKhfpb3rh3tmdf0i9ibyfddsavv` FOREIGN KEY (`entreprise_client_id`) REFERENCES `entreprise_client` (`id`),
  CONSTRAINT `FKj4jrmdev5qkq749n1kr4y0h3n` FOREIGN KEY (`boutique_id`) REFERENCES `boutique` (`id`),
  CONSTRAINT `FKjmaw7sj2qhcq1ly8xbiqkjbvo` FOREIGN KEY (`caisse_id`) REFERENCES `caisse` (`id`),
  CONSTRAINT `FKqo5gk9u6opb1ng6jobfli7ld4` FOREIGN KEY (`vendeur_id`) REFERENCES `user` (`id`),
  CONSTRAINT `FKt8c0ckr8dqeq9nia3wb7j6r7n` FOREIGN KEY (`client_id`) REFERENCES `client` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=683 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
